console.log('\n\x1b[1m── v4.99.53 — D.2 QUIZ UI + RESULTS PLACEHOLDER ──\x1b[0m');

const _dxQuizD2Raw = fs.readFileSync(path.join(ROOT, 'landing/diagnostic/network-plus/quiz.html'), 'utf8');
